-- Run this in your Supabase SQL editor to set up the storage table.

CREATE TABLE IF NOT EXISTS app_storage (
  key        TEXT PRIMARY KEY,
  value      TEXT NOT NULL,
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Optional: enable Row Level Security (open access for single-user / no-auth app)
ALTER TABLE app_storage ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all operations" ON app_storage
  FOR ALL USING (true) WITH CHECK (true);

-- ── Vocabulary ───────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS vocabulary (
  id         INT PRIMARY KEY,
  term       TEXT NOT NULL,
  meaning    TEXT NOT NULL,
  example    TEXT,
  category   TEXT NOT NULL DEFAULT 'general'
);

ALTER TABLE vocabulary ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow all operations" ON vocabulary
  FOR ALL USING (true) WITH CHECK (true);

ON CONFLICT (id) DO NOTHING;

-- ── Interview Questions ──────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS interview_questions (
  id         INT PRIMARY KEY,
  question   TEXT NOT NULL,
  answer     TEXT NOT NULL,
  category   TEXT NOT NULL
);

ALTER TABLE interview_questions ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow all operations" ON interview_questions
  FOR ALL USING (true) WITH CHECK (true);

ON CONFLICT (id) DO NOTHING;
