INSERT INTO vocabulary (id, term, meaning, example, category) VALUES
(1, 'Algorithm', 'A step-by-step procedure for solving a problem or accomplishing a task', 'A sorting algorithm arranges elements in order.', 'general'),
(2, 'API', 'Application Programming Interface — a set of rules that allows programs to communicate', 'We use the REST API to fetch user data from the server.', 'general'),
(3, 'Database', 'An organized collection of structured information stored electronically', 'We store user profiles in a PostgreSQL database.', 'general'),
(4, 'Framework', 'A foundational structure providing pre-built components and conventions for development', 'React is a JavaScript framework for building UIs.', 'general'),
(5, 'Debug', 'The process of finding and fixing errors or bugs in code', 'I spent two hours debugging the null pointer exception.', 'general'),
(6, 'Abstraction', 'Hiding complex implementation details behind a simpler interface', 'A car driver uses the steering wheel without knowing engine internals — that is abstraction.', 'general'),
(7, 'Agile', 'An iterative software development methodology emphasizing flexibility and collaboration', 'Our team follows Agile with two-week sprints.', 'general'),
(8, 'Authentication', 'The process of verifying the identity of a user or system', 'Login with username and password is a form of authentication.', 'general'),
(9, 'Authorization', 'Determining what actions or resources a verified user is allowed to access', 'Only admins are authorized to delete records.', 'general'),
(10, 'Backend', 'Server-side code and infrastructure that handles data processing and business logic', 'Node.js powers the backend API of our application.', 'general'),
(11, 'Bandwidth', 'The maximum rate at which data can be transferred over a network', 'Streaming 4K video requires high bandwidth.', 'general'),
(12, 'Binary', 'A base-2 number system using only digits 0 and 1, fundamental to computing', 'The number 5 in binary is 101.', 'general'),
(13, 'Boolean', 'A data type with only two possible values: true or false', 'isLoggedIn is a boolean variable.', 'general'),
(14, 'Cache', 'Temporary high-speed storage for frequently accessed data to improve performance', 'We cache API responses to reduce server load.', 'general'),
(15, 'CLI', 'Command Line Interface — a text-based interface for interacting with a computer', 'Use the CLI to run git commands.', 'general'),
(16, 'Compiler', 'A program that translates source code into machine code before execution', 'GCC compiles C code into an executable binary.', 'general'),
(17, 'Concurrency', 'Multiple tasks executing in overlapping time periods, sharing resources', 'Concurrency allows a web server to handle multiple requests simultaneously.', 'general'),
(18, 'Deployment', 'The process of releasing and installing software into a production environment', 'We deploy to AWS every Friday after testing.', 'general'),
(19, 'Docker', 'A platform for packaging applications into isolated containers with their dependencies', 'Docker ensures the app runs the same on every machine.', 'general'),
(20, 'Encryption', 'Converting data into an unreadable format to protect it from unauthorized access', 'HTTPS uses TLS encryption to protect data in transit.', 'general'),
(21, 'Git', 'A distributed version control system for tracking changes in source code', 'Use git commit to save your changes locally.', 'general'),
(22, 'HTTP', 'HyperText Transfer Protocol — the foundation of data communication on the web', 'The browser sends an HTTP GET request to fetch a webpage.', 'general'),
(23, 'IDE', 'Integrated Development Environment — software combining code editor, debugger, and build tools', 'VS Code is a popular IDE for web development.', 'general'),
(24, 'JSON', 'JavaScript Object Notation — a lightweight, human-readable data interchange format', 'APIs often return data as JSON: {"name": "Alice", "age": 30}', 'general'),
(25, 'Kubernetes', 'An open-source container orchestration platform for automating deployment and scaling', 'Kubernetes manages our microservices cluster in production.', 'general'),
(26, 'Latency', 'The delay between a request being made and the response being received', 'High latency causes lag in online gaming.', 'general'),
(27, 'Library', 'A collection of pre-written reusable code modules for common tasks', 'Lodash is a utility library with helpful functions.', 'general'),
(28, 'Memory Leak', 'A bug where a program fails to release memory it no longer needs, causing gradual resource exhaustion', 'The memory leak caused the app to crash after running for 24 hours.', 'general'),
(29, 'Middleware', 'Software that connects different systems or acts as intermediary between components', 'Express middleware handles authentication before routing.', 'general'),
(30, 'Module', 'A self-contained unit of code with a specific purpose that can be imported and reused', 'Each feature is in its own module for maintainability.', 'general'),
(31, 'REST', 'Representational State Transfer — an architectural style for designing networked APIs', 'GET /users/1 is a RESTful endpoint to fetch user with id 1.', 'general'),
(32, 'Runtime', 'The period when a program is executing; also the environment that executes the code', 'Node.js is a JavaScript runtime built on Chrome''s V8 engine.', 'general'),
(33, 'SDK', 'Software Development Kit — a set of tools and libraries for building applications on a platform', 'We use the AWS SDK to interact with S3 buckets.', 'general'),
(34, 'SQL', 'Structured Query Language — a language for managing and querying relational databases', 'SELECT * FROM users WHERE active = true; is a SQL query.', 'general'),
(35, 'SSL/TLS', 'Security protocols providing encrypted communication over a network', 'Websites with HTTPS use SSL/TLS certificates.', 'general'),
(36, 'Thread', 'The smallest unit of execution within a process, enabling parallel operations', 'A multi-threaded server handles each request in a separate thread.', 'general'),
(37, 'Token', 'A string credential (often JWT) used for authenticating API requests', 'Include the Bearer token in the Authorization header.', 'general'),
(38, 'Version Control', 'A system for tracking and managing changes to files over time', 'Git is the most widely used version control system.', 'general'),
(39, 'Webhook', 'An HTTP callback that notifies your app when a specific event occurs in another system', 'GitHub sends a webhook to our CI server when code is pushed.', 'general'),
(40, 'Recursion', 'A programming technique where a function calls itself to solve smaller subproblems', 'Factorial of n = n * factorial(n-1) is a classic recursion example.', 'general'),
(41, 'Inheritance', 'An OOP concept where a class derives properties and methods from a parent class', 'Dog extends Animal, inheriting the breathe() method.', 'general'),
(42, 'Polymorphism', 'The ability for objects of different types to be treated as instances of a common interface', 'A draw() method works differently for Circle and Square objects.', 'general'),
(43, 'Encapsulation', 'Bundling data and methods together and restricting direct access to internal state', 'Private class fields are a form of encapsulation.', 'general'),
(44, 'Microservice', 'A small, independently deployable service focused on a single business function', 'Our app has separate microservices for auth, payments, and notifications.', 'general'),
(45, 'GraphQL', 'A query language for APIs that allows clients to request exactly the data they need', 'With GraphQL, you can fetch user name and email in one query.', 'general'),
(46, 'WebSocket', 'A protocol providing full-duplex communication channels over a single TCP connection', 'Chat applications use WebSockets for real-time messaging.', 'general'),
(47, 'CDN', 'Content Delivery Network — distributed servers delivering content from locations near users', 'Cloudflare CDN reduces latency by caching assets globally.', 'general'),
(48, 'DNS', 'Domain Name System — translates human-readable domain names to IP addresses', 'DNS resolves "google.com" to 142.250.64.14.', 'general'),
(49, 'Load Balancer', 'A device that distributes incoming traffic across multiple servers to ensure reliability', 'The load balancer routes requests to the least-busy server.', 'general'),
(50, 'CI/CD', 'Continuous Integration and Continuous Delivery — automating testing and deployment pipelines', 'Our CI/CD pipeline runs tests and deploys on every merge to main.', 'general'),
(51, 'Containerization', 'Packaging an application with all its dependencies into a portable, isolated unit', 'Docker containerization ensures consistent environments across dev and prod.', 'general'),
(52, 'Scalability', 'The ability of a system to handle increased workload by adding resources', 'Horizontal scalability adds more servers as traffic grows.', 'general'),
(53, 'Refactoring', 'Restructuring existing code to improve readability and maintainability without changing behavior', 'We refactored the payment module to reduce code duplication.', 'general'),
(54, 'Unit Test', 'A test that validates a single function or component in isolation from the rest of the system', 'We write unit tests for each utility function using Jest.', 'general'),
(55, 'Dependency Injection', 'Providing dependencies to a class from the outside rather than creating them internally', 'Injecting a database connection into a service enables easier testing.', 'general'),
(56, 'Design Pattern', 'A reusable solution template for a commonly occurring software design problem', 'The Observer pattern is used in event-driven systems.', 'general'),
(57, 'MVC', 'Model-View-Controller — an architectural pattern separating data, UI, and control logic', 'Rails and Django follow the MVC pattern.', 'general'),
(58, 'CORS', 'Cross-Origin Resource Sharing — a browser security mechanism controlling cross-domain requests', 'Add CORS headers to allow your frontend to call the API.', 'general'),
(59, 'OAuth', 'An open standard protocol for secure access delegation without sharing passwords', '"Login with Google" uses OAuth 2.0.', 'general'),
(60, 'JWT', 'JSON Web Token — a compact, URL-safe token for transmitting authentication claims', 'The server issues a JWT after login; the client sends it with each request.', 'general'),
(61, 'Hash Function', 'A function that maps input data of any size to a fixed-size output value', 'bcrypt is a hash function used to store passwords securely.', 'general'),
(62, 'Queue', 'A FIFO data structure where elements are added at the back and removed from the front', 'A print queue processes jobs in the order they arrive.', 'general'),
(63, 'Stack (DS)', 'A LIFO data structure where the last element added is the first to be removed', 'Function calls use a call stack to track execution context.', 'general'),
(64, 'HashMap', 'A key-value data structure providing O(1) average lookup, insert, and delete operations', 'Use a HashMap to count word frequencies in O(n) time.', 'general'),
(65, 'Regex', 'Regular Expression — a pattern for matching, searching, and manipulating strings', '/^[a-z0-9]+@[a-z]+\.com$/ is a regex for validating email.', 'general'),
(66, 'Promise', 'A JavaScript object representing the eventual completion or failure of an asynchronous operation', 'fetch() returns a Promise that resolves with the response.', 'general'),
(67, 'Async/Await', 'Syntactic sugar over Promises that makes asynchronous code look synchronous', 'const data = await fetch(url).then(r => r.json());', 'general'),
(68, 'Big O Notation', 'A mathematical notation describing how algorithm performance scales with input size', 'Binary search runs in O(log n) time.', 'general'),
(69, 'Garbage Collection', 'Automatic memory management that frees memory no longer referenced by the program', 'JavaScript uses garbage collection to manage heap memory.', 'general'),
(70, 'Deadlock', 'A state where two or more threads are blocked forever, each waiting for the other to release a resource', 'Thread A holds lock 1 and waits for lock 2; Thread B holds lock 2 and waits for lock 1.', 'general'),
(71, 'Race Condition', 'A bug where the outcome depends on the unpredictable timing of multiple threads accessing shared data', 'Two threads reading and incrementing a counter without a lock causes a race condition.', 'general'),
(72, 'TCP/IP', 'The foundational protocol suite for internet communication providing reliable data delivery', 'HTTP runs over TCP/IP to ensure packets arrive in order.', 'general'),
(73, 'UDP', 'User Datagram Protocol — a connectionless transport protocol that prioritizes speed over reliability', 'Video streaming uses UDP to minimize latency despite some packet loss.', 'general'),
(74, 'SSH', 'Secure Shell — a cryptographic protocol for secure remote login and command execution', 'ssh user@server.com connects securely to a remote machine.', 'general'),
(75, 'DevOps', 'A set of practices combining software development and IT operations for faster delivery', 'DevOps teams use CI/CD pipelines to ship features daily.', 'general'),
(76, 'Singleton', 'A design pattern ensuring a class has only one instance throughout the application', 'A database connection pool is often implemented as a singleton.', 'general'),
(77, 'Proxy', 'An intermediary server or object that intercepts requests to another resource', 'A reverse proxy like Nginx forwards requests to backend services.', 'general'),
(78, 'Repository', 'A storage location for source code, packages, or data with history tracking', 'The project repository is hosted on GitHub.', 'general'),
(79, 'Event Loop', 'A mechanism that handles asynchronous callbacks in single-threaded environments like JavaScript', 'The event loop allows Node.js to handle thousands of connections concurrently.', 'general'),
(80, 'Monolith', 'A single, unified application where all components are tightly coupled and deployed together', 'Our legacy app is a monolith — we are migrating it to microservices.', 'general'),
(81, 'Cloud Computing', 'Delivering computing services like storage, servers, and software over the internet on demand', 'AWS and Azure are the leading cloud computing platforms.', 'general'),
(82, 'Virtualization', 'Creating virtual versions of hardware resources to run multiple OS instances on one machine', 'VMware provides virtualization for running multiple virtual machines.', 'general'),
(83, 'Linked List', 'A linear data structure where each node contains data and a pointer to the next node', 'Inserting at the head of a linked list is O(1).', 'general'),
(84, 'Binary Tree', 'A tree data structure where each node has at most two children: left and right', 'A binary search tree allows O(log n) search operations.', 'general'),
(85, 'Mutex', 'A synchronization primitive that prevents multiple threads from accessing a shared resource simultaneously', 'Acquire the mutex before reading shared memory to prevent data corruption.', 'general'),
(86, 'I2C', 'Inter-Integrated Circuit — a two-wire serial protocol (SDA + SCL) supporting multiple devices on one bus', 'The temperature sensor uses I2C to communicate with the MCU.', 'iot'),
(87, 'SPI', 'Serial Peripheral Interface — a four-wire synchronous protocol (MOSI, MISO, SCK, CS) for high-speed communication', 'The display module uses SPI for faster data transfer than I2C.', 'iot'),
(88, 'UART', 'Universal Asynchronous Receiver-Transmitter — asynchronous serial communication using TX and RX lines', 'We use UART to send debug logs from the microcontroller to a PC.', 'iot'),
(89, 'GPIO', 'General Purpose Input/Output — digital pins on a microcontroller that can be configured as input or output', 'Toggle the LED by writing HIGH to a GPIO pin.', 'iot'),
(90, 'MCU', 'Microcontroller Unit — a single integrated circuit containing a CPU, memory, and programmable I/O peripherals', 'The STM32 MCU runs the motor control firmware.', 'iot'),
(91, 'ADC', 'Analog-to-Digital Converter — converts continuous analog signals to discrete digital values', 'Read the analog temperature sensor through the ADC at 12-bit resolution.', 'iot'),
(92, 'DAC', 'Digital-to-Analog Converter — converts discrete digital values back to continuous analog signals', 'Use the DAC to output a sine wave for the audio amplifier.', 'iot'),
(93, 'DMA', 'Direct Memory Access — allows peripherals to transfer data to/from memory without CPU intervention', 'Configure DMA for UART to receive data without interrupting the CPU.', 'iot'),
(94, 'RTOS', 'Real-Time Operating System — an OS that guarantees task execution within strict timing constraints', 'FreeRTOS schedules tasks with deterministic timing for motor control.', 'iot'),
(95, 'Watchdog Timer', 'A hardware timer that resets the system if the software fails to periodically reset it, preventing lockups', 'Pet the watchdog every 500ms or the MCU will reset automatically.', 'iot'),
(96, 'Bootloader', 'A small program that loads the main application firmware into memory on device startup', 'The bootloader checks for OTA updates before launching the main firmware.', 'iot'),
(97, 'Firmware', 'Low-level software embedded in hardware devices that controls device-specific functions', 'We flashed updated firmware to fix the sensor calibration bug.', 'iot'),
(98, 'PWM', 'Pulse Width Modulation — a technique using variable duty cycle pulses to control power to devices', 'Use PWM to control LED brightness or motor speed.', 'iot'),
(99, 'Interrupt', 'A signal that causes the CPU to pause its current task and execute a specific interrupt handler', 'Configure a GPIO interrupt to detect button presses immediately.', 'iot'),
(100, 'MQTT', 'Message Queuing Telemetry Transport — a lightweight publish/subscribe messaging protocol for IoT', 'The sensor publishes temperature to the MQTT broker every 5 seconds.', 'iot'),
(101, 'CoAP', 'Constrained Application Protocol — a RESTful web transfer protocol designed for constrained IoT devices', 'CoAP uses UDP to minimize overhead on low-power sensors.', 'iot'),
(102, 'Zigbee', 'A low-power, low-data-rate wireless mesh networking protocol for IoT and smart home devices', 'Zigbee smart bulbs form a mesh network in the smart home.', 'iot'),
(103, 'Bluetooth LE', 'Bluetooth Low Energy — a wireless protocol optimized for battery-powered IoT devices with low data rates', 'The fitness tracker uses BLE to sync data to your smartphone.', 'iot'),
(104, 'LoRaWAN', 'Long Range Wide Area Network — a protocol for long-range, low-power wireless communication in IoT', 'LoRaWAN sensors in smart agriculture transmit data up to 15 km away.', 'iot'),
(105, 'Edge Computing', 'Processing data near its source rather than sending it to the cloud, reducing latency and bandwidth', 'Edge computing on the factory floor analyzes sensor data in real time.', 'iot'),
(106, 'OTA Update', 'Over-The-Air — wirelessly delivering firmware or software updates to deployed devices', 'We push OTA updates to fix bugs without physically accessing the devices.', 'iot'),
(107, 'CAN Bus', 'Controller Area Network — a robust vehicle/industrial bus for microcontrollers to communicate without a host', 'CAN Bus connects ECUs in a car to share sensor and control data.', 'iot'),
(108, 'Modbus', 'A serial communication protocol widely used in industrial automation and SCADA systems', 'The PLC reads sensor values from the remote I/O over Modbus RTU.', 'iot'),
(109, 'PLC', 'Programmable Logic Controller — a ruggedized industrial computer for automating manufacturing processes', 'The PLC controls the conveyor belt speed based on sensor inputs.', 'iot'),
(110, 'Sensor Fusion', 'Combining data from multiple sensors to produce more accurate and reliable measurements', 'Sensor fusion from accelerometer + gyroscope gives stable orientation data.', 'iot'),
(111, 'Deep Sleep', 'An ultra-low power state where most MCU peripherals are disabled to extend battery life', 'Enter deep sleep between readings to achieve 2-year battery life.', 'iot'),
(112, 'LwIP', 'Lightweight IP — a small TCP/IP stack designed for embedded systems with limited resources', 'LwIP provides TCP/IP networking on an MCU with 64KB RAM.', 'iot'),
(113, 'Flash Memory', 'Non-volatile storage used in embedded systems to persist firmware and data across power cycles', 'Store configuration parameters in flash memory so they survive reboot.', 'iot'),
(114, 'EEPROM', 'Electrically Erasable Programmable Read-Only Memory — byte-addressable non-volatile memory for small data', 'Save calibration offsets to EEPROM so they persist after power-off.', 'iot'),
(115, 'ISR', 'Interrupt Service Routine — a function that executes immediately when an interrupt signal is received', 'Keep the ISR short and fast; set a flag and handle logic in the main loop.', 'iot'),
(116, 'Polling', 'Repeatedly checking a device or flag status in a loop instead of using interrupts', 'Polling the UART status register wastes CPU cycles compared to interrupts.', 'iot'),
(117, 'HAL', 'Hardware Abstraction Layer — an API providing a uniform interface to hardware, easing portability', 'Use HAL_GPIO_WritePin() instead of direct register access for portability.', 'iot'),
(118, 'JTAG', 'Joint Test Action Group — a standard interface for debugging and programming embedded systems', 'Use a JTAG debugger to step through firmware and inspect registers.', 'iot'),
(119, 'Volatile Keyword', 'A C/C++ qualifier telling the compiler not to optimize accesses to a variable that can change externally', 'Declare ISR-updated flags as volatile to prevent compiler optimization.', 'iot'),
(120, 'Endianness', 'The byte ordering convention used to store multi-byte values: big-endian (MSB first) or little-endian (LSB first)', 'Convert between network (big-endian) and host byte order with htons().', 'iot'),
(121, 'CRC', 'Cyclic Redundancy Check — an error-detecting code used to verify data integrity in communications', 'Append a CRC32 checksum to each data packet to detect transmission errors.', 'iot'),
(122, 'Semaphore', 'An RTOS synchronization primitive used to signal between tasks or limit resource access', 'Use a binary semaphore to signal when new sensor data is ready.', 'iot'),
(123, 'Message Queue', 'An RTOS mechanism for passing data safely between tasks using a buffered FIFO structure', 'Send sensor readings via message queue to the processing task.', 'iot'),
(124, 'Memory Map', 'A layout describing how memory regions (flash, RAM, peripherals) are addressed in an embedded system', 'Refer to the datasheet memory map to find the GPIO base address.', 'iot'),
(125, 'Cross-compilation', 'Compiling code on one architecture (host) to run on a different target architecture', 'Cross-compile for ARM Cortex-M4 using the arm-none-eabi-gcc toolchain.', 'iot'),
(126, 'Device Tree', 'A data structure describing hardware topology in embedded Linux systems to decouple board support from kernel', 'Enable the I2C peripheral in the device tree overlay.', 'iot'),
(127, 'NFC', 'Near Field Communication — a short-range wireless protocol for data exchange within 4 cm', 'Tap your phone to the NFC tag to configure the IoT device.', 'iot'),
(128, 'Matter Protocol', 'A smart home interoperability standard allowing devices from different vendors to work together', 'The new smart plug supports Matter, so it works with Alexa, Google, and Apple.', 'iot'),
(129, 'Power Management', 'Techniques to minimize energy consumption in embedded and IoT devices to extend battery life', 'Implement power management by shutting off unused peripherals during idle.', 'iot'),
(130, 'Register (HW)', 'A small, fast storage location inside a processor or peripheral used to control hardware behavior', 'Write to the control register to configure the timer peripheral.', 'iot'),
(131, 'BSP', 'Board Support Package — a layer of software providing drivers and configuration for a specific hardware board', 'The BSP initializes clocks and pinmux before the application starts.', 'iot'),
(132, 'Task Priority', 'A value assigned to RTOS tasks determining scheduling order when multiple tasks are ready to run', 'Assign higher priority to the motor control task than the logging task.', 'iot'),
(133, 'Linker Script', 'A configuration file controlling how the linker places code and data sections in memory', 'The linker script maps .text to flash and .data to RAM.', 'iot'),
(134, 'Tick Rate', 'The frequency at which an RTOS timer interrupt fires, determining the minimum task scheduling resolution', 'A 1000 Hz tick rate gives 1 ms scheduling resolution in FreeRTOS.', 'iot'),
(135, 'Wi-Fi', 'A wireless networking technology using radio waves to provide high-speed internet access', 'The ESP32 connects to Wi-Fi to upload sensor data to the cloud.', 'iot'),
(136, 'Thread Safety', 'Property of code that functions correctly during simultaneous execution by multiple threads', 'Use a mutex to make the shared buffer thread-safe.', 'iot'),
(137, 'Embedded Linux', 'A version of the Linux kernel adapted and configured for embedded systems with limited resources', 'The Raspberry Pi runs Embedded Linux to manage the display and sensors.', 'iot'),
(138, 'Protocol Stack', 'A set of layered protocols implementing a network communication standard', 'The TCP/IP protocol stack handles all network communication in LwIP.', 'iot'),
(139, 'Datasheet', 'Technical document from the manufacturer describing a component''s specifications, electrical characteristics, and usage', 'Consult the STM32 datasheet for GPIO electrical characteristics.', 'iot'),
(140, 'PWM Duty Cycle', 'The percentage of time a PWM signal is high within one period, controlling average output power', 'A 50% duty cycle on a 5V PWM signal produces an average of 2.5V.', 'iot'),
(141, 'ICSP', 'In-Circuit Serial Programming — a method for programming microcontrollers while installed in a circuit', 'Use ICSP to flash the bootloader onto the bare AVR chip.', 'iot'),
(142, 'SWD', 'Serial Wire Debug — a two-pin ARM debugging interface alternative to JTAG with lower pin count', 'Connect ST-Link via SWD to debug the STM32 firmware.', 'iot'),
(143, 'Z-Wave', 'A wireless mesh protocol for smart home devices operating in the sub-GHz band for better range', 'Z-Wave door sensors report status to the smart home hub.', 'iot'),
(144, 'TinyML', 'Running machine learning inference on microcontrollers and edge devices with milliwatts of power', 'TinyML on the MCU classifies vibration patterns to detect machine faults.', 'iot'),
(145, 'RS-485', 'A balanced differential serial bus standard for multi-point communication over long distances', 'RS-485 connects 32 nodes over 1200 meters in an industrial network.', 'iot'),
(146, 'Current Draw', 'The amount of electric current consumed by a circuit or component, critical for battery life calculations', 'Measure current draw in deep sleep to verify the 10 μA target.', 'iot'),
(147, 'Pull-up Resistor', 'A resistor connecting a signal line to a supply voltage, ensuring a defined HIGH state when floating', 'I2C lines require pull-up resistors for correct logic levels.', 'iot'),
(148, 'Debouncing', 'Filtering out spurious multiple transitions from mechanical switches to register a single clean press', 'Software debouncing ignores button state changes within 20 ms.', 'iot'),
(149, 'Clock Speed', 'The frequency at which a processor executes instructions, measured in MHz or GHz', 'The STM32 runs at up to 168 MHz clock speed.', 'iot'),
(150, 'Interrupt Priority', 'A numeric ranking determining which interrupt service routine runs first when multiple interrupts occur simultaneously', 'Set emergency shutdown interrupt to highest priority.', 'iot')
INSERT INTO interview_questions (id, question, answer, category) VALUES
(1, 'Tell me about yourself.', 'I am a software engineer with a passion for embedded systems and IoT development. I have experience working with microcontrollers like STM32 and ESP32, writing firmware in C/C++, and integrating cloud connectivity using MQTT and REST APIs. I enjoy solving complex hardware-software challenges and thrive in cross-functional teams where I can collaborate with both hardware engineers and backend developers.', 'behavioral'),
(2, 'What are your greatest strengths?', 'My greatest strengths are systematic problem-solving and attention to detail, which are critical in embedded development where bugs can be hard to reproduce. I am also a strong communicator — I can translate technical concepts for both engineering teams and non-technical stakeholders. Additionally, I am proactive about learning; when I encounter an unfamiliar protocol like LoRaWAN or Matter, I invest time to understand it deeply before implementing.', 'behavioral'),
(3, 'What is your greatest weakness?', 'I can sometimes over-engineer solutions by considering edge cases that may never occur in practice. I have been working on this by applying the YAGNI principle — building only what is needed now and refactoring when requirements evolve. This has made me faster at delivering initial implementations while keeping code maintainable.', 'behavioral'),
(4, 'Describe a challenging technical problem you solved.', 'On a recent IoT project, our device was intermittently resetting in the field but worked fine on the bench. Through systematic debugging — examining the watchdog reset log, adding more instrumentation, and stress-testing under temperature extremes — I identified a stack overflow in a low-priority RTOS task triggered only under heavy sensor load. I fixed it by increasing the task stack size and adding a stack watermark monitor. The devices have been stable since deployment.', 'behavioral'),
(5, 'Where do you see yourself in 5 years?', 'In five years, I see myself as a senior engineer or technical lead specializing in IoT system architecture. I want to have shipped products that impact thousands of users, deepened my expertise in real-time systems and wireless protocols, and mentored junior engineers. I am also interested in exploring the intersection of ML at the edge and resource-constrained devices.', 'behavioral'),
(6, 'Why do you want this position?', 'This role aligns perfectly with my skills in embedded firmware and IoT connectivity, and I am excited by the opportunity to work on products that directly improve people''s lives. I am drawn to your company''s focus on low-power design — it is a technical area I genuinely enjoy. I also appreciate the team''s culture of engineering excellence and continuous learning evident from your engineering blog.', 'behavioral'),
(7, 'What is an API and how does it work?', 'An API (Application Programming Interface) is a defined contract that allows two software systems to communicate. One system exposes endpoints or functions; the other calls them to request data or trigger actions. For example, a RESTful HTTP API receives requests at a URL like GET /sensors/1, processes the query, and returns a JSON response. The caller does not need to know the internal implementation — just the interface.', 'technical'),
(8, 'Explain the difference between REST and GraphQL.', 'REST uses fixed endpoints (one URL per resource) and the server determines what data is returned. GraphQL uses a single endpoint where the client specifies exactly which fields it needs in the query, preventing over-fetching or under-fetching of data. REST is simpler and cacheable by default; GraphQL is more flexible and reduces network round trips when you need data from multiple related resources. For IoT dashboards with varied data views, GraphQL can be advantageous.', 'technical'),
(9, 'What is Docker and why would you use it?', 'Docker is a containerization platform that packages an application with all its dependencies into a lightweight, portable container. This ensures the application runs identically across development, staging, and production environments. In IoT backends, Docker is valuable for running MQTT brokers, time-series databases, and microservices in isolated containers. It also simplifies CI/CD pipelines since each build produces a deterministic image.', 'technical'),
(10, 'Explain the difference between I2C and SPI.', 'I2C uses two wires (SDA for data, SCL for clock) and supports multiple devices on the same bus using 7-bit addresses. It is slower (up to ~400 kHz standard) but requires fewer pins, making it ideal for sensors. SPI uses four wires (MOSI, MISO, SCK, CS) and is faster (up to tens of MHz) but requires a dedicated chip-select line for each device. Use I2C for low-speed sensors; use SPI for displays, ADCs, or flash memory where throughput matters.', 'iot'),
(11, 'How do you minimize power consumption in an IoT device?', 'I apply several strategies: (1) Use deep sleep between sensor readings — wake on a timer or external interrupt only. (2) Disable unused peripherals and clock domains. (3) Select a low-power MCU rated for sub-microamp sleep current. (4) Minimize radio transmission time — batch data and use efficient protocols like LoRaWAN or BLE. (5) Optimize firmware — avoid busy-waiting, use DMA for transfers. (6) Profile actual current draw with a power monitor like the Nordic PPK2.', 'iot'),
(12, 'What is MQTT and why is it popular for IoT?', 'MQTT (Message Queuing Telemetry Transport) is a lightweight publish-subscribe messaging protocol designed for constrained devices and unreliable networks. Devices publish messages to topics on a broker (e.g., Mosquitto); subscribers receive messages on those topics. It is popular in IoT because it has a minimal header overhead (~2 bytes), supports QoS levels for delivery guarantees, handles intermittent connectivity gracefully with persistent sessions, and scales to millions of connected devices.', 'iot'),
(13, 'Explain interrupt-driven vs polling approaches.', 'Polling means the CPU continuously checks a peripheral status register in a loop, wasting cycles even when no event has occurred. Interrupt-driven means the peripheral signals the CPU only when an event occurs, and the CPU executes an ISR to handle it. Interrupts are more efficient for infrequent events (e.g., button presses, UART receive), while polling can be acceptable for very fast, predictable events where interrupt overhead would dominate. In RTOS systems, interrupts are preferred to keep tasks responsive.', 'iot'),
(14, 'What is an RTOS and when do you need one?', 'An RTOS (Real-Time Operating System) provides deterministic task scheduling with guaranteed response times, unlike general-purpose OSes. It offers preemptive multitasking, inter-task communication (queues, semaphores), and timing services. You need an RTOS when your application has multiple concurrent tasks with different deadlines — for example, a device that simultaneously controls a motor (hard real-time), reads sensors (periodic), and handles Wi-Fi communication (bursty). For simple single-task firmware, a bare-metal super-loop suffices.', 'iot'),
(15, 'How do you approach debugging a firmware crash?', 'First, I capture the fault context — check if a watchdog reset occurred and read the fault status registers (e.g., ARM CFSR, HFSR). I enable HardFault handlers to capture the stack frame and PC at the time of crash. I then use the debugger (GDB/JTAG) to examine the stack and identify the faulting instruction. Common root causes include stack overflow, NULL pointer dereference, unaligned memory access, or corrupted function pointers. I also use stack canaries and enable MPU protection zones to catch issues earlier.', 'iot')
